shape.script:
function getHandles(params) {
    let lineWidth = params.lineWidth;
    let end = params.end;
    let start = params.start;
    let dx = end.x-start.x;
    let dy = end.y-start.y;
    let dlen = Math.hypot(dx,dy);
    let nx = dx / dlen;
    let ny = dy / dlen;
    let cwX = -dy / dlen;
    let cwY = dx / dlen;
    let ccwX = dy / dlen;
    let ccwY = -dx / dlen;
    return {
        s: params.start,
        e: params.end,
        lw: {
            x: start.x + cwX * lineWidth + dx/3,
            y: start.y + cwY * lineWidth + dy/3,
            axis:[cwX,cwY]
        }
    }
}

function getPath(params) {
    let lineWidth = params.lineWidth;
    let end = params.end;
    let start = params.start;
    let dx = end.x-start.x;
    let dy = end.y-start.y;
    let dlen = Math.hypot(dx,dy);
    let nx = dx / dlen;
    let ny = dy / dlen;
    let cwX = -dy / dlen;
    let cwY = dx / dlen;
    let ccwX = dy / dlen;
    let ccwY = -dx / dlen;
    return [
        [start.x + cwX * lineWidth, start.y + cwY * lineWidth],
        [start.x + ccwX * lineWidth, start.y + ccwY * lineWidth],
        [end.x + ccwX * lineWidth, end.y + ccwY * lineWidth],
        [end.x + cwX * lineWidth, end.y + cwY * lineWidth],
        {closed:true}
    ];
}
